INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (105311, 0, 0.5, "よし、なかなかいい仕上がりだ！\n絵を描くのも悪くないな！\n時々子どものイタズラだと\n思われるのは心外だが……", 0, 1, 1112009, 11, 1, 1112, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 1112010, 91, "", 1112, "");
