INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (104011, 0, 0.5, "えへへ、きちんと上手に描けました。\n黙々と作業するのは嫌いじゃないです。\nでも……私なんかの絵で本当に\n喜んでもらえるんですかね？", 0, 1, 2612009, 11, 1, 2612, 10);
