INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (107011, 0, 0.5, "ふむ……こんなところでしょうか。\n模倣するのには慣れているつもりですが\n絵にすると少し勝手が違うものですね。", 0, 1, 3812009, 11, 1, 3812, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 3812010, 91, "", 3812, "");
