INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (106611, 0, 0.5, "このっ、このやろっ！\nここをこうしてフィニ～ッシュ！\nふぅ。ボスへの怒り……じゃなくて\n街への想いを込めた傑作ができたです。", 0, 1, 4012009, 11, 1, 4012, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 4012010, 91, "", 4012, "");
