INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (103811, 0, 0.5, "ゆっくり、時間をかけちゃいましたけど\nこれで完成、です。\nふふっ、絵を描くのって楽しいですね。", 0, 1, 4312009, 11, 1, 4312, 10);
