INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (106011, 0, 0.5, "う～ん……最近少し絵柄が\n変わってきた気がするわね？\nなんだか【美食殿】のみんなに\n影響されてるような……？", 0, 1, 8812009, 11, 1, 8812, 10);
