INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100711, 0, 0.5, "描き終わったの！\nプリンプリン～♪\n今日もこのあとアイツに\nプリンをもらうの～！", 0, 1, 10312009, 11, 1, 10312, 10);
