INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (103011, 0, 0.5, "シュバッ！　シュバババッ！\n色塗りはワタシにお任せデース！\nこの絵筆二刀流で、瞬く間に\nカラフルにしてみせマース！", 0, 1, 16412030, 11, 1, 16412, 10);
