INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (107111, 0, 0.5, "よぉし、文句なしの出来栄えだ！\nしかし【カルミナ】はさておき、\n【王宮騎士団（NIGHTMARE）】\nまで引き続きお絵描きとはな。", 0, 1, 16912009, 11, 1, 16912, 10);
