INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (107111, 0, 0.5, "まったく、分かっていないな！\n芸術とは感性の爆発だ、勢い任せだ！\n宴の始まりに狂喜乱舞するかの如く、\n本能のまま描くのが最良なんだぞ☆", 0, 1, 17812037, 11, 1, 17812, 10);
