INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100911, 0, 0.5, "見るがいい、シグルドよ！\n熾炎戦鬼煉獄血盟暗黒団にふさわしい、\n運命の交わりを感じさせるような\n大作に仕上がったぞ！！", 0, 1, 18712009, 11, 1, 18712, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 18712010, 91, "", 18712, "");
