INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100911, 0, 0.5, "さらにここに、我らの生きた証として、\n前世からの宿命を感じさせる刻印を……\nえっ、公共の壁だからそれはダメ？\nそうか……残念だ……", 0, 1, 18712012, 11, 1, 18712, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 18712013, 91, "", 18712, "");
