INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (104911, 0, 0.5, "お姉ちゃんのお姉ちゃんによる、\nお姉ちゃん史を覆す芸術が完成したよ！\n弟くんも一目見ただけで、この絵から\nお姉ちゃんを感じてくれるよね？", 0, 1, 19112009, 11, 1, 19112, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 19112010, 91, "", 19112, "");
