INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100811, 0, 0.5, "はぁ……困ってしまったな。\n確かに絵の方は文句のない仕上がり\nなんだけれど。", 0, 1, 19612009, 11, 1, 19612, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 19612010, 91, "", 19612, "");
