INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100811, 0, 0.5, "絵を描いているときのボクと、\n描き終わった後のボク。\nどちらのボクがより美しいのか\n悩んでるんだ。キミはどっちだと思う？", 0, 1, 19612012, 11, 1, 19612, 10);
