INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (111011, 0, 0.5, "しかし何だな、この作業……\nぼく個人の芸術性は不要と言うなら、\nぼくが筆を持つ必然はあるのだろうか。", 0, 1, 21112009, 11, 1, 21112, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 21112010, 91, "", 21112, "");
