INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (111011, 0, 0.5, "いや、だが、これは国家事業だ。\n端的に換言すれば、金のためだ。\n商業と創作の狭間で葛藤するぼく──\nおお、まさに芸術家ならではの苦悩！", 0, 1, 21112013, 11, 1, 21112, 10);
