INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (104011, 0, 0.5, "おわりました～……\nやっぱり、絵を描くのはいいですね。\nぼっちが一人で絵を描いてても、\nそんなに違和感ないですから。", 0, 1, 21412009, 11, 1, 21412, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 21412010, 91, "", 21412, "");
