INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (101111, 0, 0.5, "今日もたくさん描きましたよ！\n壁に絵を描くのって大変かなって\n最初は思ってたんですけど……\n私、分かっちゃったんですよ！", 0, 1, 23312009, 11, 1, 23312, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 23312010, 91, "", 23312, "");
