INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (101111, 0, 0.5, "手を動かしながら考えて\n色んな人と協力する所もあったりして\nこれってお裁縫と似てるんです！\nすごいですよね、お兄ちゃん！", 0, 1, 23312012, 11, 1, 23312, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 23312013, 91, "", 23312, "");
