INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (106811, 0, 0.5, "権能、解放。\nオブジェクト……\nなぁんてね、ウソウソ。\nちゃんと自分の手で仕上げたよ。", 0, 1, 23412009, 11, 1, 23412, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 23412010, 91, "", 23412, "");
