INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100811, 0, 0.5, "はぁ、思わずため息が出るよ。\nかわいいボクが、美しい絵を描く。\nただそれだけで、言葉にできないほど\n尊い場面になってしまうよね？", 0, 1, 23812026, 11, 1, 23812, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 23812027, 91, "", 23812, "");
