INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100511, 0, 0.5, "ホントにランドソルって広いッスよね～\nみんなで壁に絵を描いてるはずなのに、\nまだまだ終わりが見えないッス。", 0, 1, 25512009, 11, 1, 25512, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 25512010, 91, "", 25512, "");
