INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (101711, 0, 0.5, "やっぱり踊って歌いながら絵を描くのは\nでーじ楽しいさ～♪\nもっと踊って……え？\n絵の具がはねちゃってる～？", 0, 1, 26612009, 11, 1, 26612, 10);
