INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (104411, 0, 0.5, "やはりこの姿だと、作業しやすいのう！\nふふっ、これもお主のおかげじゃな。\nどれ、少しなら褒美をやっても良いぞ？\nなに……絵を見れるだけで十分じゃと？", 0, 1, 27312009, 11, 1, 27312, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 27312010, 91, "", 27312, "");
