INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100811, 0, 0.5, "ふふっ、頬についた絵の具すら、\nボクを魅力的に見せちゃうね♪\nそれどころか、何か新しいメイクの\n参考になるかもしれないよ♪", 0, 1, 27612009, 11, 1, 27612, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 27612010, 91, "", 27612, "");
