INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100611, 0, 0.5, "こんな感じでいいのかな～？\n何回かこのお仕事してるけど、いっつも\n物足りなく感じちゃうんですよね。\nもう少しかわいい雰囲気にしたいな～", 0, 1, 29312009, 11, 1, 29312, 10);
