INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (104411, 0, 0.5, "こうした作業は、慣れてくると\n捻ったことがしたくなるもの……\nわらわも、もう少し凝った表現に\n挑戦してみるかのう。", 0, 1, 29512009, 11, 1, 29512, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 29512010, 91, "", 29512, "");
