INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100711, 0, 0.5, "ずーっとお絵描きしてるけど、いつも\n同じ数のプリンしかもらえないの～……\n絶対、まだあるのに隠してるの～！\nケチくさいの～！", 0, 1, 29612009, 11, 1, 29612, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 29612010, 91, "", 29612, "");
