INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100711, 0, 0.5, "ミヤコが真面目にお仕事するなんて、\nとっても珍しいことなの。だから\nご褒美に、もっとたくさんの\nプリンをよこすべきなの～！", 0, 1, 29612012, 11, 1, 29612, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 29612013, 91, "", 29612, "");
