INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (103111, 0, 0.5, "……そういえば、この壁画は\n彷徨える霊たちの間でも、\n話題になっているようですよ？", 0, 1, 29712009, 11, 1, 29712, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 29712010, 91, "", 29712, "");
