INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (103111, 0, 0.5, "こういった温かみのある絵は、\n死者の魂さえ魅了する何かが\nあるのかもしれません。\n彼らの癒しとなればよいのですが。", 0, 1, 29712012, 11, 1, 29712, 10);
