INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100611, 0, 0.5, "最近、もうすっかりお絵描きに\nハマっちゃいました～♪\n筆とか絵の具とかも自分で買って、\nおうちでもお絵描きしてるんですよ？", 0, 1, 30912009, 11, 1, 30912, 10);
