INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100211, 0, 0.5, "絵がきれいでも、ゴミがあったり、\n雑草だらけだったら残念だから。\n……えっ、手伝ってくれるの？\nありがとう、騎士クンは優しいね♪", 0, 1, 33412012, 11, 1, 33412, 10);
