INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (104411, 0, 0.5, "ふぅ……\n絵を描くのに体を動かしたせいか、\nちと喉が渇いたのう。\nなにか飲み物を持っておらんか？", 0, 1, 33512009, 11, 1, 33512, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 33512010, 91, "", 33512, "");
