INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (103111, 0, 0.5, "大勢で絵を描く、という試みは\n素晴らしいものなのですが、参加者に\n女性が多いのは困りものですね。\n主に、父が原因なのですが。", 0, 1, 33612009, 11, 1, 33612, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 33612010, 91, "", 33612, "");
