INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100611, 0, 0.5, "きゃあっ！\nもう、せっかく絵が完成したのに、\nペンキの缶を倒しちゃうなんて～！", 0, 1, 33712009, 11, 1, 33712, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 33712010, 91, "", 33712, "");
