INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (102211, 0, 0.5, "……この仕事って、気を付けないと\n服が塗料で汚れちゃうのが困るわね。\n昨日はアカリが思いっきり汚してきて、\nお説教する羽目になったし。", 0, 1, 33812009, 11, 1, 33812, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 33812010, 91, "", 33812, "");
