INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (102211, 0, 0.5, "そう、お説教したばっかりなのよ……\nなのに、今日に限って私もスカートに\n思いっきりペンキが跳ねるなんて！\nあの子になんて言い訳するのよ～！？", 0, 1, 33812012, 11, 1, 33812, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 33812013, 91, "", 33812, "");
