INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (105011, 0, 0.5, "身だしなみがだらしないと、\nレディに相応しい男の子になれないわ。\n石鹸を取ってきてあげるから、\nそこで待ってなさい。", 0, 1, 33912012, 11, 1, 33912, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 33912013, 91, "", 33912, "");
