INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (103311, 0, 0.5, "こういう、でっけぇ絵を眺めてると、\n心が洗われるような気分になるべな～\nなんだか、爽やかな傑作ギャグを\n思いつけそうな気がしてきたべ！", 0, 1, 34112009, 11, 1, 34112, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 34112010, 91, "", 34112, "");
