INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100211, 0, 0.5, "そういえば、騎士クンも\nすごく絵を描くのが上手になったよね。\nさ、最初の頃は下手だったとか、\nそういうことじゃないよ？", 0, 1, 34912009, 11, 1, 34912, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 34912010, 91, "", 34912, "");
