INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100311, 0, 0.5, "絵を描くときは、静かな湖に\n釣り糸を垂らす時のように、\n穏やかな心持ちであるべきだ。", 0, 1, 35012009, 11, 1, 35012, 10);
