INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (102011, 0, 0.5, "お絵描きするときはお筆をつかうけど、\n白いふさふさのところってどうやって\n作ってるのかな……？\nえっ、どうぶつさんの毛なの？", 0, 1, 35212009, 11, 1, 35212, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 35212010, 91, "", 35212, "");
