INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (100411, 0, 0.5, "えへへ～、おわり～！\nふつう壁に絵を描いたら怒られるのに、\n逆に褒めてもらえるって不思議かも？", 0, 1, 35412009, 11, 1, 35412, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 35412010, 91, "", 35412, "");
