INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (103711, 0, 0.5, "こういう作業って慣れてくると、\nオリジナリティーを出してみたく\nなったりしない？\nこっそり魔法少女要素を足すとか。", 0, 1, 36012009, 11, 1, 36012, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 36012010, 91, "", 36012, "");
