INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (110911, 0, 0.5, "ハ？　先輩、いまなんて言いました？\nこの城壁お絵かきプロジェクトに、\nカルミナちゃんたちも参加してる？\n三人ともうっかり壁にサイン書いてた？", 0, 1, 37712009, 11, 1, 37712, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 37712010, 91, "", 37712, "");
