INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (110911, 0, 0.5, "あのさあ……カルミナ創作小話は\nチエルもよく匿名で投稿しますけども、\n現実に反したお馬鹿キャラみたいな\n解釈広めるのはやめましょうよ。ね？", 0, 1, 37712012, 11, 1, 37712, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 37712013, 91, "", 37712, "");
