INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (111011, 0, 0.5, "おい諸君、大変だ。\n国家予算こと我々の労働報酬について\nギルド管理協会に問い合わせたところ、\nそんなもん出ねえ的な回答があった。", 0, 1, 37912021, 11, 1, 37912, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 37912022, 91, "", 37912, "");
