INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (110911, 0, 0.5, "またまた～！　そんなのアレですよ、\nそう言われてうちらがワーワー騒いでる\nところに、後ろからカリンねえさんが\nプラカード持って出てくるやつですよ。", 0, 1, 37912026, 11, 1, 37912, 10);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (0, "", "", "", "", "", 37912027, 91, "", 37912, "");
