INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (105111, 0, 0.5, "いよいよ、この仕事も\n終わりが近づいてきたんじゃない？\n大きな壁だったけれど、みんなで\n協力したら、あっという間だったわね。", 0, 1, 40412009, 11, 1, 40412, 10);
